49	static double polevl(double x, const double coef[], int N)
50	{
51	    double ans;
52	    const double *p = coef;
53	    int i = N;
54	
55	    ans = *p++;
56	    do
57	        ans = ans * x + *p++;
58	    while(--i);
59	
60	    return ans ;
61	}
62	
63	double p1evl(double x, const double coef[], int N)
64	{
65	    double ans;
66	    const double *p = coef;
67	    int i = N - 1;
68	
69	    ans = x + *p++;
70	    do
71	        ans = ans * x + *p++;
72	    while(--i);
73	
74	    return ans;
75	}
