77	#define THPIO4 2.35619449019234492885
78	#define SQ2OPI .79788456080286535588
79	#define Z1 1.46819706421238932572E1
80	#define Z2 4.92184563216946036703E1
81	
82	static double _bessel_j1(double x)
83	{
84	    double w, z, p, q, xn;
85	    const double RP[4] = {
86	        -8.99971225705559398224E8,
87	        4.52228297998194034323E11,
88	        -7.27494245221818276015E13,
89	        3.68295732863852883286E15,
90	    };
91	    const double RQ[8] = {
92	        6.20836478118054335476E2,
93	        2.56987256757748830383E5,
94	        8.35146791431949253037E7,
95	        2.21511595479792499675E10,
96	        4.74914122079991414898E12,
97	        7.84369607876235854894E14,
98	        8.95222336184627338078E16,
99	        5.32278620332680085395E18,
100	    };
101	    const double PP[7] = {
102	        7.62125616208173112003E-4,
103	        7.31397056940917570436E-2,
104	        1.12719608129684925192E0,
105	        5.11207951146807644818E0,
106	        8.42404590141772420927E0,
107	        5.21451598682361504063E0,
108	        1.00000000000000000254E0,
109	    };
110	    const double PQ[7] = {
111	        5.71323128072548699714E-4,
112	        6.88455908754495404082E-2,
113	        1.10514232634061696926E0,
114	        5.07386386128601488557E0,
115	        8.39985554327604159757E0,
116	        5.20982848682361821619E0,
117	        9.99999999999999997461E-1,
118	    };
119	    const double QP[8] = {
120	        5.10862594750176621635E-2,
121	        4.98213872951233449420E0,
122	        7.58238284132545283818E1,
123	        3.66779609360150777800E2,
124	        7.10856304998926107277E2,
125	        5.97489612400613639965E2,
126	        2.11688757100572135698E2,
127	        2.52070205858023719784E1,
128	    };
129	    const double QQ[7] = {
130	        7.42373277035675149943E1,
131	        1.05644886038262816351E3,
132	        4.98641058337653607651E3,
133	        9.56231892404756170795E3,
134	        7.99704160447350683650E3,
135	        2.82619278517639096600E3,
136	        3.36093607810698293419E2,
137	    };
138	
139	    w = x;
140	    if (x < 0)
141	        w = -x;
142	
143	    if (w <= 5.0) {
144	        z = x * x;
145	        w = polevl(z, RP, 3) / p1evl(z, RQ, 8);
146	        w = w * x * (z - Z1) * (z - Z2);
147	        return w ;
148	    }
149	
150	    w = 5.0 / x;
151	    z = w * w;
152	    p = polevl(z, PP, 6) / polevl(z, PQ, 6);
153	    q = polevl(z, QP, 7) / p1evl(z, QQ, 7);
154	    xn = x - THPIO4;
155	    p = p * cos(xn) - w * q * sin(xn);
156	    return p * SQ2OPI / sqrt(x);
157	}
