164	#define CASE_FOURIER_OUT_RC(_TYPE, _type, _T, _po, _tmp) \
165	case _TYPE:                                          \
166	    NPY_CSETREAL##_T((_type *)_po, tmp);                      \
167	    NPY_CSETIMAG##_T((_type *)_po, 0.0);                      \
168	    break
