177	case _TYPE:                                                             \
178	    _tmp_r = npy_creal##_t(*((_type *)_pi)) * _tmp;                               \
179	    _tmp_i = npy_cimag##_t(*((_type *)_pi)) * _tmp;                               \
180	    break
