187	int NI_FourierFilter(PyArrayObject *input, PyArrayObject* parameter_array,
188	                     npy_intp n, int axis, PyArrayObject* output,
189	                     int filter_type)
190	{
191	    NI_Iterator ii, io;
192	    char *pi, *po;
193	    double *parameters = NULL, **params = NULL;
194	    npy_intp kk, hh, size;
195	    npy_double *iparameters = (void *)PyArray_DATA(parameter_array);
196	    NPY_BEGIN_THREADS_DEF;
197	
198	    /* precalculate the parameters: */
199	    parameters = malloc(PyArray_NDIM(input) * sizeof(double));
200	    if (!parameters) {
201	        PyErr_NoMemory();
202	        goto exit;
203	    }
204	    for (kk = 0; kk < PyArray_NDIM(input); kk++) {
205	        /* along the direction of the real transform we must use the given
206	             length of that dimensions, unless a complex transform is assumed
207	             (n < 0): */
208	        int shape = kk == axis ?
209	                (n < 0 ? PyArray_DIM(input, kk) : n) : PyArray_DIM(input, kk);
210	        switch (filter_type) {
211	            case _NI_GAUSSIAN:
212	                parameters[kk] = *iparameters++ * M_PI / (double)shape;
213	                parameters[kk] = -2.0 * parameters[kk] * parameters[kk];
214	                break;
215	            case _NI_ELLIPSOID:
216	            case _NI_UNIFORM:
217	                parameters[kk] = *iparameters++;
218	                break;
219	        }
220	    }
221	    /* allocate memory for tables: */
222	    params = malloc(PyArray_NDIM(input) * sizeof(double*));
223	    if (!params) {
224	        PyErr_NoMemory();
225	        goto exit;
226	    }
227	    for (kk = 0; kk < PyArray_NDIM(input); kk++) {
228	        params[kk] = NULL;
229	    }
230	    for (kk = 0; kk < PyArray_NDIM(input); kk++) {
231	        if (PyArray_DIM(input, kk) > 1 || filter_type == _NI_ELLIPSOID) {
232	            params[kk] = malloc(PyArray_DIM(input, kk) * sizeof(double));
233	            if (!params[kk]) {
234	                PyErr_NoMemory();
235	                goto exit;
236	            }
237	        }
238	    }
239	
240	    NPY_BEGIN_THREADS;
241	
242	    switch (filter_type) {
243	        case _NI_GAUSSIAN:
244	            /* calculate the tables of exponentials: */
245	            for (hh = 0; hh < PyArray_NDIM(input); hh++) {
246	                if (params[hh]) {
247	                    if (hh == axis && n >= 0) {
248	                        for (kk = 0; kk < PyArray_DIM(input, hh); kk++) {
249	                            double tmp = parameters[hh] * kk * kk;
250	                            params[hh][kk] = fabs(tmp) > 50.0 ? 0.0 : exp(tmp);
251	                        }
252	                    }
253	                    else {
254	                        const npy_intp dim = PyArray_DIM(input, hh);
255	                        int jj = 0;
256	                        for (kk = 0; kk < (dim + 1) / 2; kk++) {
257	                            double tmp = parameters[hh] * kk * kk;
258	                            params[hh][jj++] =
259	                                            fabs(tmp) > 50.0 ? 0.0 : exp(tmp);
260	                        }
261	                        for (kk = -(dim / 2); kk < 0; kk++) {
262	                            double tmp = parameters[hh] * kk * kk;
263	                            params[hh][jj++] =
264	                                            fabs(tmp) > 50.0 ? 0.0 : exp(tmp);
265	                        }
266	                    }
267	                }
268	            }
269	            break;
270	        case _NI_UNIFORM:
271	            /* calculate the tables of parameters: */
272	            for (hh = 0; hh < PyArray_NDIM(input); hh++) {
273	                if (params[hh]) {
274	                    params[hh][0] = 1.0;
275	                    if (hh == axis && n >= 0) {
276	                        double tmp = M_PI * parameters[hh] / n;
277	                        for (kk = 1; kk < PyArray_DIM(input, hh); kk++) {
278	                            params[hh][kk] = tmp > 0.0 ?
279	                                             sin(tmp * kk) / (tmp * kk) : 0.0;
280	                        }
281	                    }
282	                    else {
283	                        const npy_intp dim = PyArray_DIM(input, hh);
284	                        double tmp = M_PI * parameters[hh] / dim;
285	                        int jj = 1;
286	                        for (kk = 1; kk < (dim + 1) / 2; kk++) {
287	                            params[hh][jj++] = tmp > 0.0 ?
288	                                            sin(tmp * kk) / (tmp * kk) : 0.0;
289	                        }
290	                        for (kk = -(dim / 2); kk < 0; kk++) {
291	                            params[hh][jj++] = tmp > 0.0 ?
292	                                            sin(tmp * kk) / (tmp * kk) : 0.0;
293	                        }
294	                    }
295	                }
296	            }
297	            break;
298	        case _NI_ELLIPSOID:
299	            /* calculate the tables of parameters: */
300	            for (hh = 0; hh < PyArray_NDIM(input); hh++) {
301	                if (params[hh]) {
302	                    params[hh][0] = 1.0;
303	                    if (hh == axis && n >= 0) {
304	                        double tmp = M_PI * parameters[hh] / n;
305	                        for (kk = 0; kk < PyArray_DIM(input, hh); kk++) {
306	                            params[hh][kk] = (double)kk * tmp;
307	                        }
308	                    }
309	                    else {
310	                        const npy_intp dim = PyArray_DIM(input, hh);
311	                        double tmp = M_PI * parameters[hh] / dim;
312	                        int jj = 0;
313	                        for(kk = 0; kk < (dim + 1) / 2; kk++) {
314	                            params[hh][jj++] = (double)kk * tmp;
315	                        }
316	                        for(kk = -(dim / 2); kk < 0; kk++) {
317	                            params[hh][jj++] = (double)kk * tmp;
318	                        }
319	                    }
320	                }
321	                else if (PyArray_DIM(input, hh) > 0) {
322	                    params[hh][0] = 1.0;
323	                }
324	            }
325	            if (PyArray_NDIM(input) > 1)
326	                for(hh = 0; hh < PyArray_NDIM(input); hh++)
327	                    for(kk = 0; kk < PyArray_DIM(input, hh); kk++) {
328	                        params[hh][kk] *= params[hh][kk];
329	                    }
330	            break;
331	        default:
332	            break;
333	    }
334	    /* initialize input element iterator: */
335	    if (!NI_InitPointIterator(input, &ii))
336	        goto exit;
337	    /* initialize output element iterator: */
338	    if (!NI_InitPointIterator(output, &io))
339	        goto exit;
340	    pi = (void *)PyArray_DATA(input);
341	    po = (void *)PyArray_DATA(output);
342	    size = PyArray_SIZE(input);
343	    /* iterator over the elements: */
344	    for(hh = 0; hh < size; hh++) {
345	        double tmp = 1.0;
346	        switch (filter_type) {
347	        case _NI_GAUSSIAN:
348	        case _NI_UNIFORM:
349	            for (kk = 0; kk < PyArray_NDIM(input); kk++) {
350	                if (params[kk])
351	                    tmp *= params[kk][ii.coordinates[kk]];
352	            }
353	            break;
354	        case _NI_ELLIPSOID:
355	            switch (PyArray_NDIM(input)) {
356	            case 1:
357	                tmp = params[0][ii.coordinates[0]];
358	                tmp = tmp != 0 ? sin(tmp) / (tmp) : 1.0;
359	                break;
360	            case 2:
361	                tmp = 0.0;
362	                for(kk = 0; kk < 2; kk++)
363	                    tmp += params[kk][ii.coordinates[kk]];
364	                tmp = sqrt(tmp);
365	                tmp = tmp > 0.0 ? 2.0 * _bessel_j1(tmp) / tmp : 1.0;
366	                break;
367	            case 3:
368	                {
369	                    double r = 0.0;
370	                    for(kk = 0; kk < 3; kk++)
371	                        r += params[kk][ii.coordinates[kk]];
372	                    r = sqrt(r);
373	                    if (r > 0.0) {
374	                        tmp = 3.0 * (sin(r) - r * cos(r));
375	                        tmp /= r * r * r;
376	                    } else {
377	                        tmp = 1.0;
378	                    }
379	                }
380	                break;
381	            }
382	            break;
383	        default:
384	            break;
385	        }
386	        if (PyArray_TYPE(input) == NPY_CFLOAT ||
387	                PyArray_TYPE(input) == NPY_CDOUBLE) {
388	            double tmp_r = 0.0, tmp_i = 0.0;
389	            switch (PyArray_TYPE(input)) {
390	                CASE_FOURIER_FILTER_RC(NPY_CFLOAT, npy_cfloat, f,
391	                                       pi, tmp, tmp_r, tmp_i);
392	                CASE_FOURIER_FILTER_RC(NPY_CDOUBLE, npy_cdouble,,
393	                                       pi, tmp, tmp_r, tmp_i);
394	            default:
395	                NPY_END_THREADS;
396	                PyErr_SetString(PyExc_RuntimeError, "data type not supported");
397	                goto exit;
398	            }
399	            switch (PyArray_TYPE(output)) {
400	                CASE_FOURIER_OUT_CC(NPY_CFLOAT, npy_cfloat, F, po, tmp_r, tmp_i);
401	                CASE_FOURIER_OUT_CC(NPY_CDOUBLE, npy_cdouble,, po, tmp_r, tmp_i);
402	            default:
403	                NPY_END_THREADS;
404	                PyErr_SetString(PyExc_RuntimeError, "data type not supported");
405	                goto exit;
406	            }
407	        }
408	        else {
409	            switch (PyArray_TYPE(input)) {
410	                CASE_FOURIER_FILTER_RR(NPY_BOOL, npy_bool, pi, tmp);
411	                CASE_FOURIER_FILTER_RR(NPY_UBYTE, npy_ubyte, pi, tmp);
412	                CASE_FOURIER_FILTER_RR(NPY_USHORT, npy_ushort, pi, tmp);
413	                CASE_FOURIER_FILTER_RR(NPY_UINT, npy_uint, pi, tmp);
414	                CASE_FOURIER_FILTER_RR(NPY_ULONG, npy_ulong, pi, tmp);
415	                CASE_FOURIER_FILTER_RR(NPY_ULONGLONG, npy_ulonglong, pi, tmp);
416	                CASE_FOURIER_FILTER_RR(NPY_BYTE, npy_byte, pi, tmp);
417	                CASE_FOURIER_FILTER_RR(NPY_SHORT, npy_short, pi, tmp);
418	                CASE_FOURIER_FILTER_RR(NPY_INT, npy_int, pi, tmp);
419	                CASE_FOURIER_FILTER_RR(NPY_LONG, npy_long, pi, tmp);
420	                CASE_FOURIER_FILTER_RR(NPY_LONGLONG, npy_longlong, pi, tmp);
421	                CASE_FOURIER_FILTER_RR(NPY_FLOAT, npy_float, pi, tmp);
422	                CASE_FOURIER_FILTER_RR(NPY_DOUBLE, npy_double, pi, tmp);
423	            default:
424	                NPY_END_THREADS;
425	                PyErr_SetString(PyExc_RuntimeError, "data type not supported");
426	                goto exit;
427	            }
428	            switch (PyArray_TYPE(output)) {
429	                CASE_FOURIER_OUT_RR(NPY_FLOAT, npy_float, po, tmp);
430	                CASE_FOURIER_OUT_RR(NPY_DOUBLE, npy_double, po, tmp);
431	                CASE_FOURIER_OUT_RC(NPY_CFLOAT, npy_cfloat, F, po, tmp);
432	                CASE_FOURIER_OUT_RC(NPY_CDOUBLE, npy_cdouble,, po, tmp);
433	            default:
434	                NPY_END_THREADS;
435	                PyErr_SetString(PyExc_RuntimeError, "data type not supported");
436	                goto exit;
437	            }
438	        }
439	        NI_ITERATOR_NEXT2(ii, io, pi, po);
440	    }
441	
442	 exit:
443	    NPY_END_THREADS;
444	    free(parameters);
445	    if (params) {
446	        for (kk = 0; kk < PyArray_NDIM(input); kk++) {
447	            free(params[kk]);
448	        }
449	        free(params);
450	    }
451	    return PyErr_Occurred() ? 0 : 1;
452	}
