454	#define CASE_FOURIER_SHIFT_R(_TYPE, _type, _pi, _tmp, _r, _i, _cost, _sint) \
455	case _TYPE:                                                                 \
456	    _tmp = *(_type *)_pi;                                                   \
457	    _r = _tmp * _cost;                                                      \
458	    _i = _tmp * _sint;                                                      \
459	    break
460	
461	#define CASE_FOURIER_SHIFT_C(_TYPE, _type, _t, _pi, _r, _i, _cost, _sint) \
462	case _TYPE:                                                           \
463	    _r = npy_creal##_t(*((_type *)_pi)) * _cost - npy_cimag##_t(*((_type *)_pi)) * _sint; \
464	    _i = npy_creal##_t(*((_type *)_pi)) * _sint + npy_cimag##_t(*((_type *)_pi)) * _cost; \
465	    break
466	
467	int NI_FourierShift(PyArrayObject *input, PyArrayObject* shift_array,
468	            npy_intp n, int axis, PyArrayObject* output)
469	{
470	    NI_Iterator ii, io;
471	    char *pi, *po;
472	    double *shifts = NULL, **params = NULL;
473	    npy_intp kk, hh, size;
474	    npy_double *ishifts = (void *)PyArray_DATA(shift_array);
475	    NPY_BEGIN_THREADS_DEF;
476	
477	    /* precalculate the shifts: */
478	    shifts = malloc(PyArray_NDIM(input) * sizeof(double));
479	    if (!shifts) {
480	        PyErr_NoMemory();
481	        goto exit;
482	    }
483	    for (kk = 0; kk < PyArray_NDIM(input); kk++) {
484	        /* along the direction of the real transform we must use the given
485	             length of that dimensions, unless a complex transform is assumed
486	             (n < 0): */
487	        int shape = kk == axis ?
488	                (n < 0 ? PyArray_DIM(input, kk) : n) : PyArray_DIM(input, kk);
489	        shifts[kk] = -2.0 * M_PI * *ishifts++ / (double)shape;
490	    }
491	    /* allocate memory for tables: */
492	    params = malloc(PyArray_NDIM(input) * sizeof(double*));
493	    if (!params) {
494	        PyErr_NoMemory();
495	        goto exit;
496	    }
497	    for (kk = 0; kk < PyArray_NDIM(input); kk++) {
498	        params[kk] = NULL;
499	    }
500	    for (kk = 0; kk < PyArray_NDIM(input); kk++) {
501	        if (PyArray_DIM(input, kk) > 1) {
502	            params[kk] = malloc(PyArray_DIM(input, kk) * sizeof(double));
503	            if (!params[kk]) {
504	                PyErr_NoMemory();
505	                goto exit;
506	            }
507	        }
508	    }
509	
510	    NPY_BEGIN_THREADS;
511	
512	    for (hh = 0; hh < PyArray_NDIM(input); hh++) {
513	        if (params[hh]) {
514	            if (hh == axis && n >= 0) {
515	                for (kk = 0; kk < PyArray_DIM(input, hh); kk++) {
516	                    params[hh][kk] = shifts[hh] * kk;
517	                }
518	            }
519	            else {
520	                int jj = 0;
521	                for (kk = 0; kk < (PyArray_DIM(input, hh) + 1) / 2; kk++) {
522	                    params[hh][jj++] = shifts[hh] * kk;
523	                }
524	                for (kk = -(PyArray_DIM(input, hh) / 2); kk < 0; kk++) {
525	                    params[hh][jj++] = shifts[hh] * kk;
526	                }
527	            }
528	        }
529	    }
530	    /* initialize input element iterator: */
531	    if (!NI_InitPointIterator(input, &ii))
532	        goto exit;
533	    /* initialize output element iterator: */
534	    if (!NI_InitPointIterator(output, &io))
535	        goto exit;
536	    pi = (void *)PyArray_DATA(input);
537	    po = (void *)PyArray_DATA(output);
538	    size = PyArray_SIZE(input);
539	    /* iterator over the elements: */
540	    for(hh = 0; hh < size; hh++) {
541	        double tmp = 0.0, sint, cost, r = 0.0, i = 0.0;
542	        for (kk = 0; kk < PyArray_NDIM(input); kk++) {
543	            if (params[kk])
544	                tmp += params[kk][ii.coordinates[kk]];
545	        }
546	        sint = sin(tmp);
547	        cost = cos(tmp);
548	        switch (PyArray_TYPE(input)) {
549	            CASE_FOURIER_SHIFT_R(NPY_BOOL, npy_bool,
550	                                 pi, tmp, r, i, cost, sint);
551	            CASE_FOURIER_SHIFT_R(NPY_UBYTE, npy_ubyte,
552	                                 pi, tmp, r, i, cost, sint);
553	            CASE_FOURIER_SHIFT_R(NPY_USHORT, npy_ushort,
554	                                 pi, tmp, r, i, cost, sint);
555	            CASE_FOURIER_SHIFT_R(NPY_UINT, npy_uint,
556	                                 pi, tmp, r, i, cost, sint);
557	            CASE_FOURIER_SHIFT_R(NPY_ULONG, npy_ulong,
558	                                 pi, tmp, r, i, cost, sint);
559	            CASE_FOURIER_SHIFT_R(NPY_ULONGLONG, npy_ulonglong,
560	                                 pi, tmp, r, i, cost, sint);
561	            CASE_FOURIER_SHIFT_R(NPY_BYTE, npy_byte,
562	                                 pi, tmp, r, i, cost, sint);
563	            CASE_FOURIER_SHIFT_R(NPY_SHORT, npy_short,
564	                                 pi, tmp, r, i, cost, sint);
565	            CASE_FOURIER_SHIFT_R(NPY_INT, npy_int,
566	                                 pi, tmp, r, i, cost, sint);
567	            CASE_FOURIER_SHIFT_R(NPY_LONG, npy_long,
568	                                 pi, tmp, r, i, cost, sint);
569	            CASE_FOURIER_SHIFT_R(NPY_LONGLONG, npy_longlong,
570	                                 pi, tmp, r, i, cost, sint);
571	            CASE_FOURIER_SHIFT_R(NPY_FLOAT, npy_float,
572	                                 pi, tmp, r, i, cost, sint);
573	            CASE_FOURIER_SHIFT_R(NPY_DOUBLE, npy_double,
574	                                 pi, tmp, r, i, cost, sint);
575	            CASE_FOURIER_SHIFT_C(NPY_CFLOAT, npy_cfloat, f,
576	                                 pi, r, i, cost, sint);
577	            CASE_FOURIER_SHIFT_C(NPY_CDOUBLE, npy_cdouble,,
578	                                 pi, r, i, cost, sint);
579	        default:
580	            NPY_END_THREADS;
581	            PyErr_SetString(PyExc_RuntimeError, "data type not supported");
582	            goto exit;
583	        }
584	        switch (PyArray_TYPE(output)) {
585	            CASE_FOURIER_OUT_CC(NPY_CFLOAT, npy_cfloat, F, po, r, i);
586	            CASE_FOURIER_OUT_CC(NPY_CDOUBLE, npy_cdouble,, po, r, i);
587	        default:
588	            NPY_END_THREADS;
589	            PyErr_SetString(PyExc_RuntimeError, "data type not supported");
590	            goto exit;
591	        }
592	        NI_ITERATOR_NEXT2(ii, io, pi, po);
593	    }
594	
595	 exit:
596	    NPY_END_THREADS;
597	    free(shifts);
598	    if (params) {
599	        for (kk = 0; kk < PyArray_NDIM(input); kk++) {
600	            free(params[kk]);
601	        }
602	        free(params);
603	    }
604	    return PyErr_Occurred() ? 0 : 1;
605	}
